$ErrorActionPreference = "Stop"

$projectRoot = (Get-Location).Path
$databasePath = Join-Path $projectRoot "app\database.py"

$databaseBase64 = @"

"@

[System.IO.File]::WriteAllBytes(
    $databasePath,
    [System.Convert]::FromBase64String(
        ($databaseBase64 -replace "\s", "")
    )
)

$testFiles = @(
    "tests\test_order_repository.py",
    "tests\test_portfolio_repository.py",
    "tests\test_position_repository.py",
    "tests\test_scheduled_run_state_repository.py",
    "tests\test_signal_repository.py",
    "tests\test_trade_execution_repository.py",
    "tests\test_update_run_repository.py"
)

foreach ($relativePath in $testFiles) {
    $path = Join-Path $projectRoot $relativePath

    if (-not (Test-Path $path)) {
        throw "File not found: $relativePath"
    }

    $content = [System.IO.File]::ReadAllText($path)

    $updated = [System.Text.RegularExpressions.Regex]::Replace(
        $content,
        '(?m)^\s*assert\s+SCHEMA_VERSION\s*==\s*(?:10|11|SCHEMA_VERSION)\s*\r?\n?',
        ''
    )

    [System.IO.File]::WriteAllText(
        $path,
        $updated,
        [System.Text.UTF8Encoding]::new($false)
    )
}

Get-ChildItem $projectRoot -Recurse -Directory -Filter "__pycache__" |
    Remove-Item -Recurse -Force -ErrorAction SilentlyContinue

Remove-Item (
    Join-Path $projectRoot ".pytest_cache"
) -Recurse -Force -ErrorAction SilentlyContinue

Write-Host "Rollback completed."
Write-Host "app\database.py restored to SCHEMA_VERSION 10."
Write-Host "Redundant fixed-version assertions removed from 7 tests."
